import React from 'react';
import { PageHeader as CarbonPageHeader } from '@carbon/react';

const PageHeader = (props) => {
    const {
        id,
        setProps,
        children,
        className,
        ...otherProps
    } = props;

    return (
        <CarbonPageHeader
            id={id}
            className={className}
            {...otherProps}
        >
            {children}
        </CarbonPageHeader>
    );
};

PageHeader.defaultProps = {
    className: ''
};

export default PageHeader;
